import CloseSmallOutlined from '@universe-design/icons-react/CloseSmallOutlined';
import stylex from '@universe-design/stylex';
import clsx from 'clsx';
import * as React from 'react';
import type { ButtonProps } from '../../button';
import { Button } from '../../button';
import type { ListItemProps } from '../../shared/components/list';
import { ListItem, ListItemTitle } from '../../shared/components/list';
import { forwardHTMLRef } from '../../util/forwardRef';
import { useTransferContext } from '../hooks/TransferContext';
import { useTransferOptionContext } from '../hooks/TransferOptionContext';
import { sxRemoveButton, sxDisabledRemoveButton, sxOption } from '../sx';
import { optionLabel } from '../utils';

export const TransferTargetOptionRemoveButton = React.forwardRef<HTMLButtonElement, ButtonProps>((props, ref) => {
  const { option, toggle, disabled } = useTransferOptionContext();
  const { cssScope } = useTransferContext();
  const prefix = cssScope('__targetList');

  return (
    <Button
      className={clsx(`${prefix}-remove`, stylex(stylex.compose(sxRemoveButton, disabled && sxDisabledRemoveButton)))}
      type="icon"
      size="small"
      icon={<CloseSmallOutlined />}
      onClick={() => toggle(option.value)}
      ref={ref}
      {...props}
    />
  );
});

export const TransferTargetOptionLabel = forwardHTMLRef<unknown, 'div'>((props, ref) => {
  const { option } = useTransferOptionContext();
  return (
    <ListItemTitle {...props} ref={ref}>
      {optionLabel(option)}
    </ListItemTitle>
  );
});

export const TransferTargetOption = forwardHTMLRef<ListItemProps, 'li'>((props, ref) => {
  const defaultChildren = React.useMemo(() => <TransferTargetOptionLabel />, []);

  const defaultAfter = React.useMemo(() => <TransferTargetOptionRemoveButton />, []);

  const { children = defaultChildren, after = defaultAfter, ...restProps } = props;

  const { disabled } = useTransferOptionContext();

  return (
    <ListItem
      disabled={disabled}
      after={after}
      ref={ref}
      showCheckmark={false}
      {...restProps}
      sx={[sxOption, ...(props.sx ?? [])]}
    >
      {children}
    </ListItem>
  );
});
